+        [TestMethod]
+        public async Task SyncPhotoToFMSAsyncStagesRotatedPhotoInWebFileUploadDirectory()
+        {
+            await UploadPhotoInAlbumFromFileLibrary();
+
+            // Snapshot upload directory before rotation so we can detect SyncPhotoToFMSAsync's FileShare write
+            var uploadDirectory = GetWebFileUploadDirectory(ContextPortfolioId);
+            var filesBeforeRotation = new HashSet<string>(Directory.GetFiles(uploadDirectory));
+
+            await RotatePhotoInAlbum();
+
+            var newUploadFiles = Directory.GetFiles(uploadDirectory)
+                .Where(f => !filesBeforeRotation.Contains(f))
+                .ToList();
+
+            using (new AssertionScope())
+            {
+                newUploadFiles.Should().NotBeEmpty("rotated photo staged in upload dir");
+
+                // The staged file's bytes must equal the rotated photo's bytes in PhotosDirectory
+                var photosDirectory = GetPhotosDirectory();
+                var rotatedPhotoSource = Path.Combine(photosDirectory, Global.CreateFileGUIDFromGUID(m_Photo.GUID));
+                File.Exists(rotatedPhotoSource).Should().BeTrue("rotated source remains in PhotosDirectory");
+
+                var rotatedPhotoLength = new FileInfo(rotatedPhotoSource).Length;
+                newUploadFiles.Should().Contain(f => new FileInfo(f).Length == rotatedPhotoLength,
+                    "staged copy matches PhotosDirectory bytes");
+            }
+        }
+
